using System.Text;
using Spectre.Console.Cli;
using Spectre.Console.Cli.Help;
using Spectre.Console.Rendering;

namespace Develix.DataSet2Sql.Cli;

public class CustomHelpProvider(ICommandAppSettings settings) : HelpProvider(settings)
{
    private const string logoBase64 = "";
    private static readonly string logoAnsi = Encoding.UTF8.GetString(Convert.FromBase64String(logoBase64));

    public override IEnumerable<IRenderable> Write(ICommandModel model, ICommandInfo? command)
    {
        return base.Write(model, command)
            .Prepend(new ControlCodeRenderable(logoAnsi + Environment.NewLine));
    }

    private sealed class ControlCodeRenderable(string text) : IRenderable
    {
        private readonly string text = text;

        public Measurement Measure(RenderOptions options, int maxWidth) => new(text.Length, text.Length);

        public IEnumerable<Segment> Render(RenderOptions options, int maxWidth) => [Segment.Control(text)];
    }
}
